USE ecru;

DELETE FROM knowledge_guides WHERE id BETWEEN 2001 AND 2099;
DELETE FROM knowledge_fabrics WHERE id BETWEEN 1001 AND 1099;
DELETE FROM knowledge_care_labels WHERE id BETWEEN 3001 AND 3099;

INSERT INTO knowledge_fabrics (
    id, name, alias, fabric_type, warmth_score, breathability_score, comfort_score, durability_score,
    summary, properties, care_guide, suitable_seasons, suitable_occasions, keywords, source, is_active,
    created_at, updated_at
) VALUES
    (1001, '羊毛', '美丽诺羊毛,毛呢,精纺羊毛', '天然纤维', 92, 70, 85, 78, '保暖性强，适合秋冬外套、针织衫和通勤单品。', '蓬松保暖，回弹性较好，穿着有质感，但部分人群会觉得略扎。', '建议优先干洗；若手洗需冷水轻柔清洗，避免高温烘干，平铺晾干更稳妥。', '秋,冬', '通勤,正式,日常', '羊毛,秋冬,保暖,外套,针织', 'manual-tests', 1, NOW(), NOW()),
    (1002, '纯棉', '全棉,棉质,精梳棉', '天然纤维', 58, 92, 90, 82, '日常适配度高，亲肤透气，适合衬衫、T 恤和内搭。', '吸湿性好，贴肤舒适，适合高频穿着，但较容易起皱。', '可常规机洗，深浅色分开；避免长时间暴晒和过度烘干。', '春,夏,秋', '日常,通勤,周末出行', '纯棉,透气,亲肤,T恤,衬衫', 'manual-tests', 1, NOW(), NOW()),
    (1003, '亚麻', '麻料,亚麻布,麻质', '天然纤维', 42, 95, 82, 68, '清爽透气，适合炎热天气和轻松自然的夏季穿搭。', '散热快，纹理自然，视觉上有松弛感，但容易起皱。', '建议冷水轻柔清洗，脱水时间不要过长，可用蒸汽稍作整理。', '春,夏', '日常,度假,轻商务', '亚麻,夏季,清爽,透气,自然纹理', 'manual-tests', 1, NOW(), NOW()),
    (1004, '牛仔布', '牛仔,丹宁,水洗牛仔', '梭织面料', 64, 66, 78, 90, '耐穿百搭，适合休闲穿搭、外搭和有结构感的下装。', '耐磨度高，轮廓感明显，和衬衫、针织、运动鞋都容易搭配。', '建议反面清洗，减少清洗频率，自然晾干可更好保色保型。', '春,秋,冬', '日常,休闲,周末出行', '牛仔布,休闲,耐磨,外套,裤装', 'manual-tests', 1, NOW(), NOW()),
    (1005, '聚酯纤维', '涤纶,聚酯,化纤', '合成纤维', 56, 58, 70, 88, '抗皱耐穿，快干性好，常见于运动服和基础混纺单品。', '不易变形，容易打理，但透气性通常弱于天然纤维。', '可常规机洗，熨烫时使用低温，涂层或印花面料更要避免高温。', '春,夏,秋,冬', '日常,通勤,运动', '聚酯纤维,涤纶,快干,耐穿,易打理', 'manual-tests', 1, NOW(), NOW()),
    (1006, '真丝', '桑蚕丝,丝绸,丝质', '天然纤维', 48, 78, 88, 52, '柔滑细腻，垂感好，适合衬衫、连衣裙和偏正式场景。', '触感顺滑，穿着舒适，视觉上更精致，但耐磨性相对有限。', '建议冷水轻柔手洗或专业干洗，避免暴晒和高温熨烫。', '春,夏,秋', '正式,通勤,约会', '真丝,桑蚕丝,垂感,精致,衬衫,连衣裙', 'manual-tests', 1, NOW(), NOW());

INSERT INTO knowledge_guides (
    id, title, subtitle, guide_type, summary, content, author, publish_date, tags,
    cover_image_url, cover_image_caption, keywords, source, is_active, created_at, updated_at
) VALUES
    (2001, '春秋通勤叠穿建议', '温差天气下更稳妥的上班搭配思路', '通勤穿搭', '适合 16 到 24 摄氏度工作日的轻叠穿建议。', '建议以内层清爽、外层轻薄为原则。可以先用纯棉衬衫或薄针织打底，再叠一件开衫或无结构西装。颜色尽量控制在两到三种低饱和中性色内，下装选择线条更利落的西裤或半裙，这样通勤途中不显臃肿，进入空调房后也更容易调节体感。', '知识库测试素材', '2026-04-27', '春秋,通勤,叠穿,办公室', '', '', '通勤,叠穿,衬衫,开衫,西装', 'manual-tests', 1, NOW(), NOW()),
    (2002, '冬季羊毛单品养护与搭配', '保暖、显精神，又不容易穿得太厚重', '面料搭配', '围绕羊毛外套和羊毛针织的实用养护与搭配建议。', '羊毛单品适合承担冬季穿搭中的保暖核心，但外套已经有一定量感时，内层不宜再过厚，建议搭配薄针织、衬衫或简洁高领。使用频率较高时，不必每次都清洗，可通过悬挂通风和蒸汽整理恢复状态。存放时建议使用有支撑的衣架，减少肩线变形。', '知识库测试素材', '2026-04-27', '冬季,羊毛,养护,外套', '', '', '羊毛,冬季,外套,针织,养护', 'manual-tests', 1, NOW(), NOW()),
    (2003, '面试场景白衬衫搭配要点', '在正式感和亲和感之间保持平衡', '正式场景', '适合面试、答辩、正式汇报场景的白衬衫搭配建议。', '白衬衫最稳妥的搭配方式，是与深色、线条利落的下装组合，例如炭灰西裤、藏蓝半裙或直筒裤。若天气偏凉，可以叠搭薄针织或简洁西装，不建议再加体积过大的卫衣或厚外套。鞋包尽量保持低调，整体重点应放在干净、利落、可信赖的形象上。', '知识库测试素材', '2026-04-27', '面试,白衬衫,正式,答辩', '', '', '面试,白衬衫,正式,西裤,答辩', 'manual-tests', 1, NOW(), NOW());

INSERT INTO knowledge_care_labels (
    id, symbol_code, symbol_name, category, instruction_text, explanation,
    do_text, dont_text, keywords, source, is_active, created_at, updated_at
) VALUES
    (3001, 'WASH_30', '30度以下常规洗涤', '水洗', '建议使用 30 摄氏度及以下水温进行常规洗涤。', '较低水温可以减少缩水、褪色和面料损伤风险，适合多数日常服装。', '使用中性洗涤剂，优先轻柔程序。', '不要默认用热水长时间高转速清洗。', '30度,水洗,常规洗涤,低温', 'manual-tests', 1, NOW(), NOW()),
    (3002, 'HAND_WASH', '仅可手洗', '水洗', '请用冷水或微温水轻柔手洗。', '通常用于较娇贵、容易变形或带有特殊结构的衣物，机洗风险较高。', '短时浸泡，轻压去水，平整晾晒。', '不要大力揉搓、拧干或直接机洗。', '手洗,轻柔,娇贵面料,变形风险', 'manual-tests', 1, NOW(), NOW()),
    (3003, 'DO_NOT_BLEACH', '不可漂白', '漂白', '请勿使用含氯或含氧漂白剂。', '漂白剂可能破坏染料稳定性，削弱纤维强度，还可能留下不均匀色斑。', '先用中性洗涤剂做局部去渍处理。', '不要把漂白产品直接接触面料表面。', '不可漂白,去渍,颜色保护,洗护', 'manual-tests', 1, NOW(), NOW()),
    (3004, 'LOW_IRON', '低温熨烫', '熨烫', '请使用低温熨烫，必要时隔布处理。', '适用于混纺、真丝感面料、印花面料或耐热性较弱的衣物。', '先在不显眼处测试温度，再从反面轻压熨烫。', '不要长时间高温直接压在正面面料上。', '低温熨烫,隔布,反面熨烫,热敏面料', 'manual-tests', 1, NOW(), NOW()),
    (3005, 'NO_TUMBLE_DRY', '不可滚筒烘干', '晾干', '请勿使用滚筒烘干，建议自然晾干。', '高温烘干可能导致针织衫缩水、弹性纤维老化，或让表面手感变粗糙。', '根据衣物重量选择平铺或悬挂晾干。', '不要用高温机器烘干代替自然风干。', '不可烘干,自然晾干,针织,缩水', 'manual-tests', 1, NOW(), NOW()),
    (3006, 'DRY_CLEAN', '建议专业干洗', '专业清洁', '日常护理建议送专业门店干洗。', '常用于羊毛大衣、西装、带内衬或结构复杂的服装，家庭水洗容易破坏版型。', '选择可靠干洗门店，并说明面料和污渍情况。', '不要在不了解面料风险时自行水洗。', '干洗,西装,大衣,版型保护', 'manual-tests', 1, NOW(), NOW());
